import collections

class TrieNode:
    def __init__(self):
        self.children = collections.defaultdict(TrieNode)
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

class Solution:
    def findAllConcatenatedWordsInADict(self, words: list[str]) -> list[str]:
        words.sort(key=len)

        trie = Trie()
        result = []

        def can_be_concatenated(word: str) -> bool:
            n = len(word)
            if n == 0:
                return False

            dp = [False] * (n + 1)
            dp[0] = True

            for i in range(1, n + 1):
                for j in range(0, i):
                    if dp[j]:
                        sub_word = word[j:i]
                        if trie.search(sub_word):
                            # Ensure the word is formed by at least two components.
                            # If j == 0 and i == n, it means the entire word itself is being matched as a single part.
                            # We want to exclude this specific case for the *final* segment being matched.
                            if not (i == n and j == 0):
                                dp[i] = True
                                break

            return dp[n]

        for word in words:
            if len(word) == 0:
                continue

            if can_be_concatenated(word):
                result.append(word)

            trie.insert(word)

        return result
